(window.webpackJsonp=window.webpackJsonp||[]).push([[333],{960:function(n,r){n.exports="\x3c!-- \r\ntitle: FFmpeg\r\nsort: \r\n--\x3e \r\n# FFmpeg入门\r\n\r\n## 安装\r\n\r\n[FFmpeg下载](https://ffmpeg.zeranoe.com/builds/)\r\n\r\n配置环境变量至bin目录\r\n\r\n提取视频音频：`ffmpeg -i .\\*.mp4 -acodec copy -vn output.aac`\r\n\r\n> 设置声音解码器为默认，不处理视频并copy\r\n\r\n\r\n\r\n## 参数\r\n\r\n### 主要参数\r\n\r\n```powershell\r\n-i # 设定输出流\r\n-f # 设定输出格式\r\n-ss\t# 设定开始时间\r\n```\r\n\r\n### 视频参数\r\n\r\n```powershell\r\n-b # 设定视频码率，默认200kbit/s\r\n-r # 设定帧率，默认25\r\n-s # 设置宽高\r\n-aspect\t# 画面比例\r\n-vn\t# 不处理视频\r\n-vcodec # 设定视频解码器\r\n```\r\n\r\n### 音频参数\r\n\r\n```powershell\r\n-ar # 设定采样率 \r\n-ac # 设定声音的Channel数 \r\n-acodec # 设定声音编解码器，未设定时则使用与输入流相同的编解码器 \r\n-an # 不处理音频\r\n```\r\n\r\n## 使用\r\n\r\n- 格式转换\r\n\r\n  `ffmpeg -i input.mp4 output.avi`\r\n\r\n- 提取音频\r\n\r\n  `ffmpeg -i *.mp4 -acodec aac -vn output.aac`\r\n\r\n- 提取视频\r\n\r\n  `ffmpeg -i input.mp4 -vcodec copy -an output.mp4`\r\n\r\n- 视频剪裁\r\n\r\n  `ffmpeg -ss 00:00:15 -t 00:00:05 -i input.mp4 -vcodec copy -acodec copy output.mp4`\r\n\r\n- 码率控制\r\n\r\n  > fmpeg控制码率有3种选择：`-minrate -b:v -maxrate`\r\n  >\r\n  > -b:v\t平均码率\r\n  >\r\n  > `ffmpeg -i input.mp4 -b:v 2000k output.mp4`\r\n  > -bufsize \t用于设置码率控制缓冲器的大小\r\n  >\r\n  > `ffmpeg -i input.mp4 -b:v 2000k -bufsize 2000k output.mp4`\r\n  >\r\n  > -minrate -maxrate\t\t设置码率阈值\r\n  >\r\n  > `ffmpeg -i input.mp4 -b:v 2000k -bufsize 2000k -maxrate 2500k output.mp4`\r\n\r\n- 编码转换\r\n\r\n  `ffmpeg -i input.mp4 -vcodec h264 output.mp4`\r\n\r\n- 过滤器\r\n\r\n  > 添加logo：\r\n  >\r\n  > `ffmpeg -i input.mp4 -i iQIYI_logo.png -filter_complex overlay output.mp4`\r\n\r\n- 抓取视频帧\r\n\r\n  >`ffmpeg -i input.mp4 -r 1 -q:v 2 -f image2 pic-%03d.jpeg`\r\n  >\r\n  >-r \t\t每秒抓取帧数\r\n  >\r\n  >`ffmpeg -i input.mp4 -ss 00:00:20 -t 10 -r 1 -q:v 2 -f image2 pic-%03d.jpeg`\r\n  >\r\n  >设置时间段\r\n\r\n### 总结"}}]);